import { requestInfo } from "rwsdk/worker";

export const Cached = () => {
  requestInfo.response.status = 200;
  requestInfo.response.headers.set("Cache-Control", "public, max-age=3600");
  requestInfo.response.headers.set("X-Cache-Status", "HIT");

  return <p>cached page</p>;
};

import { requestInfo } from "rwsdk/worker";

export const Forbidden = () => {
  requestInfo.response.status = 403;
  requestInfo.response.headers.set("X-Reason", "forbidden");

  return <p>nope!</p>;
};

import { requestInfo } from "rwsdk/worker";

export const Teapot = () => {
  requestInfo.response.status = 418;
  requestInfo.response.headers.set("Content-Language", "en");

  return <p>I am a teapot</p>;
};

import { render, route } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";
import { Cached } from "@/app/pages/cached";
import { Forbidden } from "@/app/pages/forbidden";
import { Teapot } from "@/app/pages/teapot";

export type AppContext = {};

export default defineApp([
  setCommonHeaders(),
  ({ ctx }) => {
    // setup ctx here
    ctx;
  },
  render(Document, [
    route("/", Home),
    route("/cached", Cached),
    route("/forbidden", Forbidden),
    route("/teapot", Teapot),
  ]),
  route("/redirect-me", () => {
    return new Response(null, {
      status: 302,
      headers: { Location: "/cached" },
    });
  }),
]);
